function Retiro() {
  return (
    <ChannelSection
      id="retiro"
      n="03"
      color="blue"
      label="Canal 01 · Tradicional"
      screenLabel="03 Retiro en Efectivo"
      title={<>Retiro en efectivo.<br />La red más amplia.</>}
      lead="El destinatario recoge su dinero en la sucursal aliada más cercana — bancos, farmacias, colmados y tiendas de conveniencia en todo el país."
      body={
      <div>
          <ul style={{ listStyle: 'none', borderTop: '1px solid var(--rule)' }}>
            {[
          ['Bancos aliados', 'BHD, Banreservas, Caribe Express.'],
          ['Retail & conveniencia', 'Farmacias, colmados, estaciones de gasolina, entre otros.'],
          ['Puntos Transi', 'Farmacia Cuesta, Farma Extra, CCN, Nacional, JUMBO, Tu Meerca'],
          ['Horarios', 'Amplios — incluye sucursales de fin de semana'],
          ['Cobertura', 'Nacional · ciudades e interior']].
          map(([k, v], i) =>
          <li key={i} style={{ display: 'grid', gridTemplateColumns: '180px 1fr', padding: '18px 0', borderBottom: '1px solid var(--rule)', gap: 24, alignItems: 'baseline' }}>
                <span style={{ fontFamily: 'JetBrains Mono, monospace', fontSize: 11, color: 'var(--ink-3)', letterSpacing: '0.08em', textTransform: 'uppercase' }}>{k}</span>
                <span style={{ fontFamily: 'Space Grotesk, sans-serif', fontSize: 18, letterSpacing: '-0.01em' }}>{v}</span>
              </li>
          )}
          </ul>
        </div>
      }
      visual={<DRMap />} />);


}

